define(['jquery', 'core/log', 'mod_readaloud/cloudpoodllloader'], function ($, log, cloudpoodllloader) {
    "use strict"; // jshint ;_;
    /*
    This file sets up the cloud poodll recorder and passes on events to registered handlers
     */

    log.debug('Readaloud helper: initialising');

    return {

        opts: null,
        status: 'stopped',

        reset: function () {
            //before we reset, make sure we were initialized in the first place
            if (this.opts !== null) {
                var container = $('#' + this.opts['recorderid']);
                container.attr('data-alreadyparsed', 'false');
                container.html('');
            }
        },

        init: function (opts, on_recording_start,
                        on_recording_end,
                        on_audio_processing,
                        on_speech) {

            var that = this;
            that.opts = opts;
            var recid = opts['recorderid'];
            cloudpoodllloader.init(recid,
                function (message) {
                    switch (message.type) {
                        case 'recording':
                            if (message.action === 'started') {
                                that.startbuttonclick();
                                on_recording_start(message);

                            } else if (message.action === 'stopped') {
                                that.stopbuttonclick();
                                on_recording_end(message);
                            }
                            break;
                        case 'awaitingprocessing':
                            //awaitingprocessing fires often, but we only want to post once
                            if (that.status !== 'posted') {
                                on_audio_processing(message);
                            }
                            that.status = 'posted';
                            break;
                        case 'speech':
                                on_speech(message);
                            break;
                        case 'error':
                            alert('PROBLEM:' + message.message);
                            break;
                    }
                }
            );
        },
        stopbuttonclick: function () {
            this.status = 'stopped';
            //do something
        },
        startbuttonclick: function () {
            this.status = 'started';
            //do something
        }

    };//end of return value
});